/**
 * Parse game_maps_single.ltx and output level bounds as JSON for the Leaflet map.
 *
 * Usage: node scripts/generate-map-levels.mjs
 *
 * Output: site/public/data/map-levels.json
 *
 * Each level gets its global_rect converted from LTX coordinate space (1024x2634)
 * to pixel coordinates matching the tile pyramid generated by generate-map-tiles.mjs.
 */

import { readFileSync, writeFileSync, mkdirSync, existsSync } from "fs";
import { join } from "path";

const ROOT = join(import.meta.dirname, "..");
const LTX_PATH = join(ROOT, "game_maps_single.ltx");
const TILES_META_PATH = join(ROOT, "site", "public", "tiles", "metadata.json");
const OUT_PATH = join(ROOT, "site", "public", "data", "map-levels.json");

// Global map coordinate space from the LTX [global_map] section
const GLOBAL_W = 1024;
const GLOBAL_H = 2634;

// Human-readable level names
const LEVEL_NAMES = {
  jupiter: "Jupiter",
  jupiter_underground: "Jupiter Underground",
  k00_marsh: "Great Swamps",
  k01_darkscape: "Darkscape",
  k02_trucks_cemetery: "Truck Cemetery",
  l01_escape: "Cordon",
  l02_garbage: "Garbage",
  l03_agroprom: "Agroprom",
  l03u_agr_underground: "Agroprom Underground",
  l04_darkvalley: "Dark Valley",
  l04u_labx18: "Lab X-18",
  l05_bar: "Bar",
  l06_rostok: "Rostok",
  l07_military: "Army Warehouses",
  l08_yantar: "Yantar",
  l08u_brainlab: "Brain Lab",
  l09_deadcity: "Dead City",
  l10_limansk: "Limansk",
  l10_radar: "Radar",
  l10_red_forest: "Red Forest",
  l10u_bunker: "Bunker",
  l11_hospital: "Hospital",
  l11_pripyat: "Pripyat (SoC)",
  l12_stancia: "CNPP",
  l12_stancia_2: "CNPP-2",
  l12u_control_monolith: "Monolith Control Center",
  l12u_sarcofag: "Sarcophagus",
  l13_generators: "Generators",
  l13u_warlab: "Warlab",
  pripyat: "Pripyat (CoP)",
  zaton: "Zaton",
  labx8: "Lab X-8",
  y04_pole: "Meadow",
  fake_start: "Fake Start",
};

// Parse the LTX file
const ltx = readFileSync(LTX_PATH, "utf-8");

// Get the list of levels from [level_maps_single]
const levelListMatch = ltx.match(
  /\[level_maps_single\]\s*\n([\s\S]*?)(?=\n\[)/
);
if (!levelListMatch) {
  console.error("Could not find [level_maps_single] section");
  process.exit(1);
}

const levelIds = levelListMatch[1]
  .split("\n")
  .map((l) => l.replace(/\s*=.*/, "").trim())
  .filter(Boolean);

console.log(`Found ${levelIds.length} levels`);

// Parse each level's global_rect (the last uncommented one wins)
const levels = [];

for (const id of levelIds) {
  const sectionRe = new RegExp(
    `\\[${id.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\\]\\s*\\n([\\s\\S]*?)(?=\\n\\[|$)`
  );
  const section = ltx.match(sectionRe);
  if (!section) {
    console.warn(`  Warning: no section found for [${id}]`);
    continue;
  }

  // Find the last uncommented global_rect line
  const lines = section[1].split("\n");
  let rect = null;
  for (const line of lines) {
    const trimmed = line.trim();
    if (trimmed.startsWith(";")) continue;
    const m = trimmed.match(
      /^global_rect\s*=\s*([-\d.]+)\s*,\s*([-\d.]+)\s*,\s*([-\d.]+)\s*,\s*([-\d.]+)/
    );
    if (m) {
      rect = {
        x1: parseFloat(m[1]),
        y1: parseFloat(m[2]),
        x2: parseFloat(m[3]),
        y2: parseFloat(m[4]),
      };
    }
  }

  if (!rect) {
    console.warn(`  Warning: no global_rect for [${id}]`);
    continue;
  }

  // Underground levels have tiny rects (1-2 px) — mark them
  const w = Math.abs(rect.x2 - rect.x1);
  const h = Math.abs(rect.y2 - rect.y1);
  const isUnderground = w <= 2 && h <= 2;

  levels.push({
    id,
    name: LEVEL_NAMES[id] || id,
    underground: isUnderground,
    // Normalized coordinates (0-1 range relative to global map)
    bounds: {
      x1: rect.x1 / GLOBAL_W,
      y1: rect.y1 / GLOBAL_H,
      x2: rect.x2 / GLOBAL_W,
      y2: rect.y2 / GLOBAL_H,
    },
    // Raw LTX coordinates (for reference)
    rawRect: rect,
  });

  console.log(
    `  ${id}: ${rect.x1},${rect.y1} → ${rect.x2},${rect.y2}${isUnderground ? " (underground)" : ""}`
  );
}

// Sort: surface levels first, then underground
levels.sort((a, b) => {
  if (a.underground !== b.underground) return a.underground ? 1 : -1;
  return a.name.localeCompare(b.name);
});

const output = {
  coordinateSpace: { width: GLOBAL_W, height: GLOBAL_H },
  levels,
};

const outDir = join(ROOT, "site", "public", "data");
if (!existsSync(outDir)) mkdirSync(outDir, { recursive: true });
writeFileSync(OUT_PATH, JSON.stringify(output, null, 2));
console.log(`\nWritten ${levels.length} levels to ${OUT_PATH}`);
